// HasPicks applies the HasEdge predicate on the "picks" edge.
func HasPicks() predicate.Golfer {
	return predicate.Golfer(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, PicksTable, PicksColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPicksWith applies the HasEdge predicate on the "picks" edge with a given conditions (other predicates).
func HasPicksWith(preds ...predicate.Pick) predicate.Golfer {
	return predicate.Golfer(func(s *sql.Selector) {
		step := newPicksStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasEntries applies the HasEdge predicate on the "entries" edge.
func HasEntries() predicate.Golfer {
	return predicate.Golfer(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, EntriesTable, EntriesColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEntriesWith applies the HasEdge predicate on the "entries" edge with a given conditions (other predicates).
func HasEntriesWith(preds ...predicate.TournamentEntry) predicate.Golfer {
	return predicate.Golfer(func(s *sql.Selector) {
		step := newEntriesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Golfer) predicate.Golfer {
	return predicate.Golfer(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Golfer) predicate.Golfer {
	return predicate.Golfer(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Golfer) predicate.Golfer {
	return predicate.Golfer(sql.NotPredicates(p))
}
